CREATE OR REPLACE FUNCTION public.accept_player_contract_by_key(p_game_session_id uuid, p_player_id uuid, p_contract_key text)
 RETURNS TABLE(accept_outcome text, contract_key text, progress_status text, accepted_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_contract_id uuid;
  v_contract_key text;
  v_progress public.player_contract_progress%rowtype;
begin
  if p_game_session_id is null or p_player_id is null or length(btrim(coalesce(p_contract_key, ''))) = 0 then
    raise exception 'PLAYER_CONTRACT_ACCEPT_SCOPE_REQUIRED';
  end if;

  select contract.id, contract.contract_key
  into v_contract_id, v_contract_key
  from public.game_session_contracts contract
  join public.game_sessions game
    on game.id = contract.game_session_id
   and game.status = 'active'
  join public.players player
    on player.game_session_id = game.id
   and player.id = p_player_id
   and player.status = 'active'
  where contract.game_session_id = p_game_session_id
    and contract.contract_key = btrim(p_contract_key)
    and contract.status in ('active', 'scheduled')
    and contract.visibility in ('public', 'targeted')
    and contract.published_at is not null
    and contract.published_at <= now()
    and (contract.expires_at is null or contract.expires_at > now())
    and (
      contract.visibility = 'public'
      or exists (
        select 1
        from jsonb_array_elements_text(
          case
            when jsonb_typeof(contract.targeting_payload -> 'playerIds') = 'array'
              then contract.targeting_payload -> 'playerIds'
            else '[]'::jsonb
          end
        ) target(value)
        where upper(btrim(target.value)) = upper(p_player_id::text)
      )
      or exists (
        select 1
        from public.player_country_assignments assignment
        join public.country_profiles country
          on country.id = assignment.country_profile_id
        cross join lateral jsonb_array_elements_text(
          case
            when jsonb_typeof(contract.targeting_payload -> 'countryCodes') = 'array'
              then contract.targeting_payload -> 'countryCodes'
            else '[]'::jsonb
          end
        ) target(value)
        where assignment.game_session_id = p_game_session_id
          and assignment.player_id = p_player_id
          and assignment.status = 'active'
          and upper(btrim(target.value)) = upper(btrim(country.country_code))
      )
      or (
        player.roster_label is not null
        and exists (
          select 1
          from jsonb_array_elements_text(
            case
              when jsonb_typeof(contract.targeting_payload -> 'rosterLabels') = 'array'
                then contract.targeting_payload -> 'rosterLabels'
              else '[]'::jsonb
            end
          ) target(value)
          where upper(btrim(target.value)) = upper(btrim(player.roster_label))
        )
      )
    )
  for share;

  if not found then
    accept_outcome := 'not_available';
    contract_key := btrim(p_contract_key);
    progress_status := null;
    accepted_at := null;
    return next;
    return;
  end if;

  insert into public.player_contract_progress (
    game_session_id,
    contract_id,
    player_id,
    status
  )
  values (
    p_game_session_id,
    v_contract_id,
    p_player_id,
    'in_progress'
  )
  on conflict (game_session_id, contract_id, player_id) do nothing
  returning * into v_progress;

  if found then
    accept_outcome := 'accepted';
  else
    select progress.*
    into v_progress
    from public.player_contract_progress progress
    where progress.game_session_id = p_game_session_id
      and progress.contract_id = v_contract_id
      and progress.player_id = p_player_id
    for update;

    if not found then
      raise exception 'PLAYER_CONTRACT_ACCEPT_PROGRESS_MISSING';
    end if;

    if v_progress.status = 'available' then
      update public.player_contract_progress progress
      set status = 'in_progress'
      where progress.id = v_progress.id
        and progress.status = 'available'
      returning progress.* into v_progress;

      if found then
        accept_outcome := 'accepted';
      else
        select progress.*
        into v_progress
        from public.player_contract_progress progress
        where progress.id = v_progress.id
        for update;

        accept_outcome := case
          when v_progress.status = 'in_progress' then 'already_accepted'
          else 'locked'
        end;
      end if;
    elsif v_progress.status = 'in_progress' then
      accept_outcome := 'already_accepted';
    else
      accept_outcome := 'locked';
    end if;
  end if;

  contract_key := v_contract_key;
  progress_status := v_progress.status;
  accepted_at := v_progress.updated_at;
  return next;
end;
$function$

CREATE OR REPLACE FUNCTION public.consume_pre_auth_request_rate_limits_v1(p_buckets jsonb)
 RETURNS TABLE(allowed boolean, retry_after_seconds integer, limiting_dimension text, limit_count integer, remaining_count integer, reset_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'pg_catalog', 'public'
AS $function$
declare
  v_now timestamptz := clock_timestamp();
  v_bucket jsonb;
  v_dimension text;
  v_key_hash text;
  v_limit integer;
  v_window_seconds integer;
  v_block_seconds integer;
  v_window_started_at timestamptz;
  v_window_ends_at timestamptz;
  v_active_blocked_until timestamptz;
  v_row public.request_rate_limit_buckets%rowtype;
  v_allowed boolean := true;
  v_retry_after integer := 0;
  v_limiting_dimension text := null;
  v_limiting_limit integer := 1;
  v_limiting_remaining integer := 2147483647;
  v_limiting_reset timestamptz := v_now;
begin
  if jsonb_typeof(p_buckets) <> 'array'
    or jsonb_array_length(p_buckets) <> 2 then
    raise exception using
      errcode = '22023',
      message = 'pre-auth rate limit request requires exactly two buckets';
  end if;

  if (
    select array_agg(distinct bucket ->> 'dimension' order by bucket ->> 'dimension')
    from jsonb_array_elements(p_buckets) as buckets(bucket)
  ) <> array['action', 'ip']::text[] then
    raise exception using
      errcode = '22023',
      message = 'pre-auth rate limit dimensions must be exactly action and ip';
  end if;

  for v_bucket in
    select bucket
    from jsonb_array_elements(p_buckets) as buckets(bucket)
    order by bucket ->> 'dimension'
  loop
    if jsonb_typeof(v_bucket) <> 'object'
      or jsonb_object_length(v_bucket) <> 5
      or exists (
        select 1
        from jsonb_object_keys(v_bucket) as supplied_keys(supplied_key)
        where supplied_key not in (
          'blockSeconds',
          'dimension',
          'keyHash',
          'limit',
          'windowSeconds'
        )
      ) then
      raise exception using
        errcode = '22023',
        message = 'pre-auth rate limit bucket shape is invalid';
    end if;

    v_dimension := v_bucket ->> 'dimension';
    v_key_hash := v_bucket ->> 'keyHash';

    begin
      v_limit := (v_bucket ->> 'limit')::integer;
      v_window_seconds := (v_bucket ->> 'windowSeconds')::integer;
      v_block_seconds := (v_bucket ->> 'blockSeconds')::integer;
    exception when others then
      raise exception using
        errcode = '22023',
        message = 'pre-auth rate limit bucket values are invalid';
    end;

    if v_dimension not in ('action', 'ip')
      or v_key_hash !~ '^[0-9a-f]{64}$'
      or v_limit not between 1 and 1000000
      or v_window_seconds not between 1 and 86400
      or v_block_seconds not between 1 and 86400 then
      raise exception using
        errcode = '22023',
        message = 'pre-auth rate limit bucket values are out of bounds';
    end if;

    v_window_started_at := to_timestamp(
      floor(extract(epoch from v_now) / v_window_seconds) * v_window_seconds
    );
    v_window_ends_at := v_window_started_at
      + make_interval(secs => v_window_seconds);

    perform pg_advisory_xact_lock(
      hashtextextended(v_dimension || ':' || v_key_hash, 0)
    );

    select max(blocked_until)
    into v_active_blocked_until
    from public.request_rate_limit_buckets
    where dimension = v_dimension
      and key_hash = v_key_hash
      and blocked_until > v_now;

    delete from public.request_rate_limit_buckets
    where dimension = v_dimension
      and key_hash = v_key_hash
      and expires_at <= v_now;

    insert into public.request_rate_limit_buckets (
      dimension,
      key_hash,
      window_started_at,
      window_seconds,
      limit_count,
      request_count,
      blocked_until,
      last_request_at,
      expires_at
    ) values (
      v_dimension,
      v_key_hash,
      v_window_started_at,
      v_window_seconds,
      v_limit,
      1,
      v_active_blocked_until,
      v_now,
      greatest(
        v_window_ends_at + make_interval(secs => v_block_seconds),
        coalesce(
          v_active_blocked_until + make_interval(secs => v_block_seconds),
          v_window_ends_at
        )
      )
    )
    on conflict (dimension, key_hash, window_started_at, window_seconds)
    do update set
      limit_count = excluded.limit_count,
      request_count = case
        when request_rate_limit_buckets.blocked_until > v_now
          then request_rate_limit_buckets.request_count
        when request_rate_limit_buckets.request_count < 2147483647
          then request_rate_limit_buckets.request_count + 1
        else request_rate_limit_buckets.request_count
      end,
      blocked_until = case
        when request_rate_limit_buckets.blocked_until > v_now
          then request_rate_limit_buckets.blocked_until
        when request_rate_limit_buckets.request_count + 1 > excluded.limit_count
          then v_now + make_interval(secs => v_block_seconds)
        else null
      end,
      last_request_at = v_now,
      expires_at = greatest(
        excluded.expires_at,
        coalesce(request_rate_limit_buckets.blocked_until, v_window_ends_at)
          + make_interval(secs => v_block_seconds)
      )
    returning * into v_row;

    if v_row.blocked_until > v_now
      or v_row.request_count > v_row.limit_count then
      if ceil(extract(epoch from (
        greatest(
          coalesce(v_row.blocked_until, v_window_ends_at),
          v_window_ends_at
        ) - v_now
      )))::integer >= v_retry_after then
        v_allowed := false;
        v_retry_after := greatest(
          1,
          ceil(extract(epoch from (
            greatest(
              coalesce(v_row.blocked_until, v_window_ends_at),
              v_window_ends_at
            ) - v_now
          )))::integer
        );
        v_limiting_dimension := v_dimension;
        v_limiting_limit := v_row.limit_count;
        v_limiting_remaining := 0;
        v_limiting_reset := greatest(
          coalesce(v_row.blocked_until, v_window_ends_at),
          v_window_ends_at
        );
      end if;
    elsif v_allowed
      and greatest(0, v_row.limit_count - v_row.request_count)
        < v_limiting_remaining then
      v_limiting_dimension := null;
      v_limiting_limit := v_row.limit_count;
      v_limiting_remaining := greatest(
        0,
        v_row.limit_count - v_row.request_count
      );
      v_limiting_reset := v_window_ends_at;
    end if;
  end loop;

  return query select
    v_allowed,
    v_retry_after,
    v_limiting_dimension,
    v_limiting_limit,
    v_limiting_remaining,
    v_limiting_reset;
end;
$function$

CREATE OR REPLACE FUNCTION public.consume_request_rate_limits_v1(p_buckets jsonb)
 RETURNS TABLE(allowed boolean, retry_after_seconds integer, limiting_dimension text, limit_count integer, remaining_count integer, reset_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'pg_catalog', 'public'
AS $function$
declare
  v_now timestamptz := clock_timestamp();
  v_bucket jsonb;
  v_dimension text;
  v_key_hash text;
  v_limit integer;
  v_window_seconds integer;
  v_block_seconds integer;
  v_window_started_at timestamptz;
  v_window_ends_at timestamptz;
  v_active_blocked_until timestamptz;
  v_row public.request_rate_limit_buckets%rowtype;
  v_allowed boolean := true;
  v_retry_after integer := 0;
  v_limiting_dimension text := null;
  v_limiting_limit integer := 1;
  v_limiting_remaining integer := 2147483647;
  v_limiting_reset timestamptz := v_now;
begin
  if jsonb_typeof(p_buckets) <> 'array'
    or jsonb_array_length(p_buckets) <> 4 then
    raise exception using
      errcode = '22023',
      message = 'rate limit request requires exactly four buckets';
  end if;

  if (
    select count(distinct bucket ->> 'dimension')
    from jsonb_array_elements(p_buckets) as buckets(bucket)
  ) <> 4 then
    raise exception using
      errcode = '22023',
      message = 'rate limit dimensions must be unique';
  end if;

  for v_bucket in
    select bucket
    from jsonb_array_elements(p_buckets) as buckets(bucket)
    order by bucket ->> 'dimension'
  loop
    if jsonb_typeof(v_bucket) <> 'object'
      or jsonb_object_length(v_bucket) <> 5
      or exists (
        select 1
        from jsonb_object_keys(v_bucket) as supplied_keys(supplied_key)
        where supplied_key not in (
          'blockSeconds',
          'dimension',
          'keyHash',
          'limit',
          'windowSeconds'
        )
      ) then
      raise exception using
        errcode = '22023',
        message = 'rate limit bucket shape is invalid';
    end if;

    v_dimension := v_bucket ->> 'dimension';
    v_key_hash := v_bucket ->> 'keyHash';

    begin
      v_limit := (v_bucket ->> 'limit')::integer;
      v_window_seconds := (v_bucket ->> 'windowSeconds')::integer;
      v_block_seconds := (v_bucket ->> 'blockSeconds')::integer;
    exception when others then
      raise exception using
        errcode = '22023',
        message = 'rate limit bucket values are invalid';
    end;

    if v_dimension not in ('action', 'game', 'identity', 'ip')
      or v_key_hash !~ '^[0-9a-f]{64}$'
      or v_limit not between 1 and 1000000
      or v_window_seconds not between 1 and 86400
      or v_block_seconds not between 1 and 86400 then
      raise exception using
        errcode = '22023',
        message = 'rate limit bucket values are out of bounds';
    end if;

    v_window_started_at := to_timestamp(
      floor(extract(epoch from v_now) / v_window_seconds) * v_window_seconds
    );
    v_window_ends_at := v_window_started_at + make_interval(secs => v_window_seconds);

    -- The dimension order above and this keyed transaction lock make overlapping
    -- four-bucket requests deadlock-safe while preserving blocks across fixed
    -- window boundaries.
    perform pg_advisory_xact_lock(
      hashtextextended(v_dimension || ':' || v_key_hash, 0)
    );

    select max(blocked_until)
    into v_active_blocked_until
    from public.request_rate_limit_buckets
    where dimension = v_dimension
      and key_hash = v_key_hash
      and blocked_until > v_now;

    delete from public.request_rate_limit_buckets
    where dimension = v_dimension
      and key_hash = v_key_hash
      and expires_at <= v_now;

    insert into public.request_rate_limit_buckets (
      dimension,
      key_hash,
      window_started_at,
      window_seconds,
      limit_count,
      request_count,
      blocked_until,
      last_request_at,
      expires_at
    ) values (
      v_dimension,
      v_key_hash,
      v_window_started_at,
      v_window_seconds,
      v_limit,
      1,
      v_active_blocked_until,
      v_now,
      greatest(
        v_window_ends_at + make_interval(secs => v_block_seconds),
        coalesce(
          v_active_blocked_until + make_interval(secs => v_block_seconds),
          v_window_ends_at
        )
      )
    )
    on conflict (dimension, key_hash, window_started_at, window_seconds)
    do update set
      limit_count = excluded.limit_count,
      request_count = case
        when request_rate_limit_buckets.blocked_until > v_now
          then request_rate_limit_buckets.request_count
        when request_rate_limit_buckets.request_count < 2147483647
          then request_rate_limit_buckets.request_count + 1
        else request_rate_limit_buckets.request_count
      end,
      blocked_until = case
        when request_rate_limit_buckets.blocked_until > v_now
          then request_rate_limit_buckets.blocked_until
        when request_rate_limit_buckets.request_count + 1 > excluded.limit_count
          then v_now + make_interval(secs => v_block_seconds)
        else null
      end,
      last_request_at = v_now,
      expires_at = greatest(
        excluded.expires_at,
        coalesce(request_rate_limit_buckets.blocked_until, v_window_ends_at)
          + make_interval(secs => v_block_seconds)
      )
    returning * into v_row;

    if v_row.blocked_until > v_now
      or v_row.request_count > v_row.limit_count then
      if ceil(extract(epoch from (
        greatest(coalesce(v_row.blocked_until, v_window_ends_at), v_window_ends_at)
          - v_now
      )))::integer >= v_retry_after then
        v_allowed := false;
        v_retry_after := greatest(
          1,
          ceil(extract(epoch from (
            greatest(coalesce(v_row.blocked_until, v_window_ends_at), v_window_ends_at)
              - v_now
          )))::integer
        );
        v_limiting_dimension := v_dimension;
        v_limiting_limit := v_row.limit_count;
        v_limiting_remaining := 0;
        v_limiting_reset := greatest(
          coalesce(v_row.blocked_until, v_window_ends_at),
          v_window_ends_at
        );
      end if;
    elsif v_allowed
      and greatest(0, v_row.limit_count - v_row.request_count)
        < v_limiting_remaining then
      v_limiting_dimension := null;
      v_limiting_limit := v_row.limit_count;
      v_limiting_remaining := greatest(0, v_row.limit_count - v_row.request_count);
      v_limiting_reset := v_window_ends_at;
    end if;
  end loop;

  return query select
    v_allowed,
    v_retry_after,
    v_limiting_dimension,
    v_limiting_limit,
    v_limiting_remaining,
    v_limiting_reset;
end;
$function$

CREATE OR REPLACE FUNCTION public.convert_currency_amount(p_game_session_id uuid, p_amount numeric, p_from_currency_code text, p_to_currency_code text)
 RETURNS numeric
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_from text := upper(btrim(p_from_currency_code));
  v_to text := upper(btrim(p_to_currency_code));
  v_direct_rate numeric;
  v_inverse_rate numeric;
BEGIN
  IF p_game_session_id IS NULL THEN
    RAISE EXCEPTION 'GAME_SESSION_REQUIRED' USING errcode = 'P0001';
  END IF;

  IF p_amount IS NULL THEN
    RAISE EXCEPTION 'AMOUNT_REQUIRED' USING errcode = 'P0001';
  END IF;

  IF length(v_from) = 0 OR length(v_to) = 0 THEN
    RAISE EXCEPTION 'CURRENCY_CODE_REQUIRED' USING errcode = 'P0001';
  END IF;

  IF v_from = v_to THEN
    RETURN round(p_amount, 2);
  END IF;

  SELECT cer.rate
  INTO v_direct_rate
  FROM public.currency_exchange_rates AS cer
  WHERE cer.game_session_id = p_game_session_id
    AND cer.from_currency_code = v_from
    AND cer.to_currency_code = v_to
    AND cer.effective_at <= now()
    AND (cer.expires_at IS NULL OR cer.expires_at > now())
  ORDER BY cer.effective_at DESC
  LIMIT 1;

  IF v_direct_rate IS NOT NULL THEN
    RETURN round(p_amount * v_direct_rate, 2);
  END IF;

  SELECT cer.rate
  INTO v_inverse_rate
  FROM public.currency_exchange_rates AS cer
  WHERE cer.game_session_id = p_game_session_id
    AND cer.from_currency_code = v_to
    AND cer.to_currency_code = v_from
    AND cer.effective_at <= now()
    AND (cer.expires_at IS NULL OR cer.expires_at > now())
  ORDER BY cer.effective_at DESC
  LIMIT 1;

  IF v_inverse_rate IS NOT NULL THEN
    RETURN round(p_amount / v_inverse_rate, 2);
  END IF;

  RAISE EXCEPTION 'EXCHANGE_RATE_NOT_FOUND' USING errcode = 'P0001';
END;
$function$

CREATE OR REPLACE FUNCTION public.create_player_with_identity_and_credential(p_game_session_id uuid, p_display_name text, p_roster_label text, p_player_identifier text, p_player_identifier_normalized text, p_access_code_hash text, p_assignment_metadata jsonb DEFAULT '{}'::jsonb)
 RETURNS TABLE(player_id uuid, display_name text, roster_label text, player_identifier text, player_status text, player_created_at timestamp with time zone, player_updated_at timestamp with time zone, country_assignment_id uuid, country_profile_id uuid, country_code text, country_name text, assigned_at timestamp with time zone, credential_created_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_identifier text := nullif(btrim(coalesce(p_player_identifier, '')), '');
  v_identifier_normalized text := nullif(btrim(coalesce(p_player_identifier_normalized, '')), '');
  v_access_code_hash text := nullif(btrim(coalesce(p_access_code_hash, '')), '');
  v_created record;
  v_credential public.player_access_credentials%rowtype;
begin
  if v_identifier is null or v_identifier_normalized is null then
    raise exception 'PLAYER_IDENTIFIER_REQUIRED' using errcode = 'P0001';
  end if;

  if v_access_code_hash is null then
    raise exception 'PLAYER_ACCESS_CODE_REQUIRED' using errcode = 'P0001';
  end if;

  select *
  into v_created
  from public.create_player_with_balanced_country_assignment(
    p_game_session_id,
    p_display_name,
    p_roster_label,
    coalesce(p_assignment_metadata, '{}'::jsonb) || jsonb_build_object(
      'identityMode', 'rfid_player_id_plus_access_code_v1'
    )
  );

  update public.players
  set
    player_identifier = v_identifier,
    player_identifier_normalized = v_identifier_normalized,
    updated_at = now()
  where id = v_created.player_id
    and game_session_id = p_game_session_id;

  insert into public.player_access_credentials (
    game_session_id,
    player_id,
    normalized_student_code_hash,
    status
  )
  values (
    p_game_session_id,
    v_created.player_id,
    v_access_code_hash,
    'active'
  )
  returning * into v_credential;

  return query
  select
    v_created.player_id,
    v_created.display_name,
    v_created.roster_label,
    v_identifier,
    v_created.player_status,
    v_created.player_created_at,
    v_created.player_updated_at,
    v_created.country_assignment_id,
    v_created.country_profile_id,
    v_created.country_code,
    v_created.country_name,
    v_created.assigned_at,
    v_credential.created_at;
exception
  when unique_violation then
    if exists (
      select 1
      from public.players p
      where p.game_session_id = p_game_session_id
        and p.player_identifier_normalized = v_identifier_normalized
        and p.status = 'active'
    ) then
      raise exception 'PLAYER_IDENTIFIER_CONFLICT' using errcode = 'P0001';
    end if;

    if exists (
      select 1
      from public.player_access_credentials pac
      where pac.game_session_id = p_game_session_id
        and pac.normalized_student_code_hash = v_access_code_hash
        and pac.status = 'active'
    ) then
      raise exception 'PLAYER_ACCESS_CODE_CONFLICT' using errcode = 'P0001';
    end if;

    raise;
end;
$function$

CREATE OR REPLACE FUNCTION public.initialize_game_lifecycle_v1()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
begin
  new.lifecycle_state := coalesce(new.lifecycle_state, 'draft');
  new.status := case new.lifecycle_state
    when 'active' then 'active'
    when 'draft' then 'disabled'
    when 'paused' then 'disabled'
    when 'ended' then 'archived'
    when 'archived' then 'archived'
  end;
  if new.lifecycle_state = 'active' then
    new.started_at := coalesce(new.started_at, new.created_at, now());
  end if;
  return new;
end;
$function$

CREATE OR REPLACE FUNCTION public.is_stock_market_open_at(p_at timestamp with time zone DEFAULT now())
 RETURNS boolean
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_local timestamp without time zone;
  v_iso_day integer;
  v_local_time time without time zone;
begin
  if p_at is null then
    return false;
  end if;

  v_local := p_at at time zone 'Asia/Seoul';
  v_iso_day := extract(isodow from v_local)::integer;
  v_local_time := v_local::time;

  return v_iso_day between 1 and 5
    and v_local_time >= time '08:00'
    and v_local_time < time '17:00';
end;
$function$

CREATE OR REPLACE FUNCTION public.is_stock_market_open_at(p_game_session_id uuid, p_at timestamp with time zone DEFAULT now())
 RETURNS boolean
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_timezone text;
  v_local timestamp without time zone;
  v_iso_day integer;
  v_local_time time without time zone;
begin
  if p_game_session_id is null or p_at is null then
    return false;
  end if;

  if not exists (
    select 1
    from public.game_sessions game_session
    where game_session.id = p_game_session_id
      and game_session.status = 'active'
  ) then
    return false;
  end if;

  v_timezone := public.stock_market_timezone_for_game(p_game_session_id);
  v_local := p_at at time zone v_timezone;
  v_iso_day := extract(isodow from v_local)::integer;
  v_local_time := v_local::time;

  return v_iso_day between 1 and 5
    and v_local_time >= time '08:00'
    and v_local_time < time '17:00';
end;
$function$

CREATE OR REPLACE FUNCTION public.issue_contract_rewards_atomic_v1(p_game_session_id uuid, p_contract_id uuid, p_progress_id uuid, p_staff_user_id uuid, p_request_id text DEFAULT NULL::text)
 RETURNS TABLE(reward_issued boolean, already_issued boolean, issued_at timestamp with time zone, reward_result jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_progress public.player_contract_progress%rowtype;
  v_contract public.game_session_contracts%rowtype;
  v_existing public.contract_reward_issuances%rowtype;
  v_reward jsonb;
  v_cash jsonb;
  v_items jsonb;
  v_item jsonb;
  v_unsupported text[];
  v_amount numeric;
  v_currency_code text;
  v_account_type text;
  v_cash_ledger_entry_id uuid;
  v_cash_balance numeric;
  v_item_id_text text;
  v_item_id uuid;
  v_quantity integer;
  v_store_item public.store_items%rowtype;
  v_inventory_quantity integer;
  v_applied jsonb := '[]'::jsonb;
  v_skipped jsonb := '[]'::jsonb;
  v_result jsonb;
  v_issued_at timestamptz := now();
begin
  if p_game_session_id is null or p_contract_id is null or p_progress_id is null then
    raise exception 'CONTRACT_REWARD_SCOPE_REQUIRED' using errcode = 'P0001';
  end if;
  if p_staff_user_id is null then
    raise exception 'STAFF_USER_REQUIRED' using errcode = 'P0001';
  end if;

  select * into v_progress
  from public.player_contract_progress
  where game_session_id = p_game_session_id
    and contract_id = p_contract_id
    and id = p_progress_id
  for update;

  if not found then
    raise exception 'CONTRACT_PROGRESS_NOT_FOUND' using errcode = 'P0001';
  end if;

  if v_progress.reward_issued_at is not null then
    select * into v_existing
    from public.contract_reward_issuances
    where game_session_id = p_game_session_id
      and progress_id = p_progress_id;

    return query
    select
      false,
      true,
      v_progress.reward_issued_at,
      coalesce(
        v_existing.reward_result,
        v_progress.result_payload -> 'rewardResult',
        jsonb_build_object(
          'status', 'skipped',
          'appliedRewards', '[]'::jsonb,
          'skippedRewards', jsonb_build_array(
            jsonb_build_object('rewardType', 'all', 'reason', 'Rewards were already issued.')
          ),
          'failedRewards', '[]'::jsonb,
          'unsupportedRewardTypes', '[]'::jsonb
        )
      );
    return;
  end if;

  if v_progress.status <> 'completed' then
    raise exception 'CONTRACT_PROGRESS_NOT_COMPLETED' using errcode = 'P0001';
  end if;

  select * into v_contract
  from public.game_session_contracts
  where game_session_id = p_game_session_id
    and id = p_contract_id;

  if not found then
    raise exception 'CONTRACT_NOT_FOUND' using errcode = 'P0001';
  end if;

  v_reward := coalesce(v_contract.reward_payload, '{}'::jsonb);
  if jsonb_typeof(v_reward) <> 'object' then
    raise exception 'INVALID_CONTRACT_REWARD_PAYLOAD' using errcode = 'P0001';
  end if;

  select array_agg(key_name order by key_name)
  into v_unsupported
  from jsonb_object_keys(v_reward) as reward_keys(key_name)
  where key_name not in ('cash', 'items');

  if coalesce(array_length(v_unsupported, 1), 0) > 0 then
    raise exception 'UNSUPPORTED_CONTRACT_REWARD_TYPES: %', array_to_string(v_unsupported, ',')
      using errcode = 'P0001';
  end if;

  v_cash := v_reward -> 'cash';
  if v_cash is not null and v_cash <> 'null'::jsonb then
    if jsonb_typeof(v_cash) <> 'object' then
      raise exception 'INVALID_CONTRACT_CASH_REWARD' using errcode = 'P0001';
    end if;
    if coalesce(v_cash ->> 'amount', '') !~ '^[0-9]+([.][0-9]{1,2})?$' then
      raise exception 'INVALID_CONTRACT_CASH_REWARD_AMOUNT' using errcode = 'P0001';
    end if;

    v_amount := (v_cash ->> 'amount')::numeric;
    if v_amount <= 0 then
      raise exception 'INVALID_CONTRACT_CASH_REWARD_AMOUNT' using errcode = 'P0001';
    end if;

    v_currency_code := upper(btrim(coalesce(nullif(v_cash ->> 'currencyCode', ''), 'ECO')));
    v_account_type := btrim(coalesce(nullif(v_cash ->> 'accountType', ''), 'cash'));

    select entry.ledger_entry_id, entry.balance
    into v_cash_ledger_entry_id, v_cash_balance
    from public.record_player_ledger_entry(
      p_game_session_id,
      v_progress.player_id,
      v_account_type,
      v_amount,
      v_currency_code,
      'credit',
      'contracts',
      'contract_reward_cash',
      p_progress_id,
      'staff_user',
      p_staff_user_id,
      jsonb_build_object(
        'requestId', p_request_id,
        'contractId', p_contract_id,
        'progressId', p_progress_id,
        'rewardIssuedAt', v_issued_at,
        'source', 'issue_contract_rewards_atomic_v1'
      )
    ) as entry;

    v_applied := v_applied || jsonb_build_array(
      jsonb_build_object(
        'rewardType', 'cash',
        'ledgerEntryId', v_cash_ledger_entry_id,
        'amount', v_amount,
        'accountType', v_account_type,
        'currencyCode', v_currency_code,
        'balance', v_cash_balance
      )
    );
  end if;

  v_items := v_reward -> 'items';
  if v_items is not null and v_items <> 'null'::jsonb then
    if jsonb_typeof(v_items) <> 'array' then
      raise exception 'INVALID_CONTRACT_ITEM_REWARDS' using errcode = 'P0001';
    end if;

    for v_item in select value from jsonb_array_elements(v_items)
    loop
      if jsonb_typeof(v_item) <> 'object' then
        raise exception 'INVALID_CONTRACT_ITEM_REWARD' using errcode = 'P0001';
      end if;

      v_item_id_text := coalesce(
        nullif(v_item ->> 'storeItemId', ''),
        nullif(v_item ->> 'itemUuid', ''),
        nullif(v_item ->> 'id', '')
      );
      begin
        v_item_id := v_item_id_text::uuid;
      exception when invalid_text_representation then
        raise exception 'INVALID_CONTRACT_ITEM_REWARD_ID' using errcode = 'P0001';
      end;

      if coalesce(v_item ->> 'quantity', '') !~ '^[0-9]+$' then
        raise exception 'INVALID_CONTRACT_ITEM_REWARD_QUANTITY' using errcode = 'P0001';
      end if;
      v_quantity := (v_item ->> 'quantity')::integer;
      if v_quantity <= 0 then
        raise exception 'INVALID_CONTRACT_ITEM_REWARD_QUANTITY' using errcode = 'P0001';
      end if;

      select * into v_store_item
      from public.store_items
      where game_session_id = p_game_session_id
        and id = v_item_id
        and status = 'active'
      for update;

      if not found then
        raise exception 'CONTRACT_REWARD_STORE_ITEM_NOT_FOUND' using errcode = 'P0001';
      end if;
      if v_store_item.stock_quantity < v_quantity then
        raise exception 'CONTRACT_REWARD_STORE_ITEM_OUT_OF_STOCK' using errcode = 'P0001';
      end if;

      update public.store_items
      set stock_quantity = stock_quantity - v_quantity,
          updated_at = v_issued_at
      where game_session_id = p_game_session_id
        and id = v_item_id;

      insert into public.inventory_holdings (
        game_session_id,
        player_id,
        store_item_id,
        quantity_owned,
        quantity_reserved
      ) values (
        p_game_session_id,
        v_progress.player_id,
        v_item_id,
        v_quantity,
        0
      )
      on conflict on constraint inventory_holdings_scope_unique
      do update set
        quantity_owned = public.inventory_holdings.quantity_owned + excluded.quantity_owned,
        updated_at = v_issued_at
      returning quantity_owned into v_inventory_quantity;

      insert into public.audit_log (
        game_session_id,
        actor_type,
        actor_id,
        action,
        target_type,
        target_id,
        metadata
      ) values (
        p_game_session_id,
        'staff_user',
        p_staff_user_id,
        'contracts.contract_reward_item',
        'inventory_holding',
        v_progress.player_id,
        jsonb_build_object(
          'requestId', p_request_id,
          'contractId', p_contract_id,
          'progressId', p_progress_id,
          'playerId', v_progress.player_id,
          'storeItemId', v_item_id,
          'quantity', v_quantity,
          'quantityOwned', v_inventory_quantity
        )
      );

      v_applied := v_applied || jsonb_build_array(
        jsonb_build_object(
          'rewardType', 'item',
          'storeItemId', v_item_id,
          'itemName', v_store_item.name,
          'quantity', v_quantity,
          'quantityOwned', v_inventory_quantity
        )
      );
    end loop;
  end if;

  if jsonb_array_length(v_applied) = 0 then
    v_skipped := jsonb_build_array(
      jsonb_build_object('rewardType', 'none', 'reason', 'No reward payload was configured.')
    );
  end if;

  v_result := jsonb_build_object(
    'status', case when jsonb_array_length(v_applied) = 0 then 'skipped' else 'applied' end,
    'appliedRewards', v_applied,
    'skippedRewards', v_skipped,
    'failedRewards', '[]'::jsonb,
    'unsupportedRewardTypes', '[]'::jsonb
  );

  insert into public.contract_reward_issuances (
    game_session_id,
    contract_id,
    progress_id,
    player_id,
    issued_by_staff_user_id,
    cash_ledger_entry_id,
    reward_payload,
    reward_result,
    request_id,
    issued_at
  ) values (
    p_game_session_id,
    p_contract_id,
    p_progress_id,
    v_progress.player_id,
    p_staff_user_id,
    v_cash_ledger_entry_id,
    v_reward,
    v_result,
    nullif(btrim(coalesce(p_request_id, '')), ''),
    v_issued_at
  );

  update public.player_contract_progress
  set reward_issued_at = v_issued_at,
      result_payload = coalesce(result_payload, '{}'::jsonb) || jsonb_build_object('rewardResult', v_result),
      updated_at = v_issued_at
  where id = p_progress_id;

  insert into public.audit_log (
    game_session_id,
    actor_type,
    actor_id,
    action,
    target_type,
    target_id,
    metadata
  ) values (
    p_game_session_id,
    'staff_user',
    p_staff_user_id,
    'contracts.contract_rewards_issued',
    'player_contract_progress',
    p_progress_id,
    jsonb_build_object(
      'requestId', p_request_id,
      'contractId', p_contract_id,
      'progressId', p_progress_id,
      'playerId', v_progress.player_id,
      'rewardResult', v_result
    )
  );

  return query select true, false, v_issued_at, v_result;
end;
$function$

CREATE OR REPLACE FUNCTION public.record_idempotent_staff_ledger_adjustment_v1(p_game_session_id uuid, p_player_id uuid, p_staff_user_id uuid, p_route_key text, p_idempotency_key text, p_account_type text, p_amount numeric, p_currency_code text, p_entry_type text, p_source_domain text, p_source_action text, p_source_id uuid DEFAULT NULL::uuid, p_audit_metadata jsonb DEFAULT '{}'::jsonb)
 RETURNS TABLE(outcome text, ledger_entry_id uuid, account_balance_id uuid, account_type text, balance numeric, currency_code text, created_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_now timestamptz := now();
  v_route_key text := btrim(coalesce(p_route_key, ''));
  v_idempotency_key text := btrim(coalesce(p_idempotency_key, ''));
  v_request_hash text;
  v_idempotency public.mutation_idempotency_keys%rowtype;
  v_ledger record;
  v_cached jsonb;
begin
  if p_game_session_id is null then
    raise exception 'GAME_SESSION_REQUIRED';
  end if;
  if p_player_id is null then
    raise exception 'PLAYER_REQUIRED';
  end if;
  if p_staff_user_id is null then
    raise exception 'STAFF_USER_REQUIRED';
  end if;
  if length(v_route_key) = 0 then
    raise exception 'LEDGER_IDEMPOTENCY_ROUTE_REQUIRED';
  end if;
  if length(v_idempotency_key) = 0 then
    raise exception 'LEDGER_IDEMPOTENCY_KEY_REQUIRED';
  end if;
  if jsonb_typeof(coalesce(p_audit_metadata, '{}'::jsonb)) <> 'object' then
    raise exception 'INVALID_AUDIT_METADATA';
  end if;

  v_request_hash := encode(
    extensions.digest(
      jsonb_build_object(
        'gameSessionId', p_game_session_id,
        'playerId', p_player_id,
        'staffUserId', p_staff_user_id,
        'routeKey', v_route_key,
        'accountType', btrim(coalesce(p_account_type, '')),
        'amount', p_amount,
        'currencyCode', upper(btrim(coalesce(p_currency_code, ''))),
        'entryType', lower(btrim(coalesce(p_entry_type, ''))),
        'sourceDomain', btrim(coalesce(p_source_domain, '')),
        'sourceAction', btrim(coalesce(p_source_action, '')),
        'sourceId', p_source_id,
        'auditMetadata', coalesce(p_audit_metadata, '{}'::jsonb)
      )::text,
      'sha256'
    ),
    'hex'
  );

  insert into public.mutation_idempotency_keys (
    game_session_id,
    player_id,
    route_key,
    idempotency_key,
    request_hash,
    status,
    expires_at
  ) values (
    p_game_session_id,
    p_player_id,
    v_route_key,
    v_idempotency_key,
    v_request_hash,
    'STARTED',
    v_now + interval '30 days'
  )
  on conflict on constraint mutation_idempotency_keys_scope_unique
  do nothing;

  select key_row.*
  into v_idempotency
  from public.mutation_idempotency_keys key_row
  where key_row.game_session_id = p_game_session_id
    and key_row.player_id = p_player_id
    and key_row.route_key = v_route_key
    and key_row.idempotency_key = v_idempotency_key
  for update;

  if not found then
    raise exception 'LEDGER_IDEMPOTENCY_LOOKUP_FAILED';
  end if;

  if v_idempotency.request_hash <> v_request_hash then
    raise exception 'LEDGER_IDEMPOTENCY_CONFLICT';
  end if;

  if v_idempotency.status = 'COMPLETED' then
    v_cached := v_idempotency.response_body;
    if v_idempotency.result_id is null or jsonb_typeof(v_cached) <> 'object' then
      raise exception 'LEDGER_IDEMPOTENCY_RESULT_MISSING';
    end if;

    return query select
      'replayed'::text,
      (v_cached ->> 'ledgerEntryId')::uuid,
      (v_cached ->> 'accountBalanceId')::uuid,
      v_cached ->> 'accountType',
      (v_cached ->> 'balance')::numeric,
      v_cached ->> 'currencyCode',
      (v_cached ->> 'createdAt')::timestamptz;
    return;
  end if;

  if v_idempotency.status <> 'STARTED' then
    raise exception 'LEDGER_IDEMPOTENCY_IN_PROGRESS';
  end if;

  select *
  into v_ledger
  from public.record_player_ledger_entry(
    p_game_session_id,
    p_player_id,
    p_account_type,
    p_amount,
    p_currency_code,
    p_entry_type,
    p_source_domain,
    p_source_action,
    p_source_id,
    'staff_user',
    p_staff_user_id,
    coalesce(p_audit_metadata, '{}'::jsonb) || jsonb_build_object(
      'idempotencyKey', v_idempotency_key,
      'routeKey', v_route_key
    )
  );

  v_cached := jsonb_build_object(
    'ledgerEntryId', v_ledger.ledger_entry_id,
    'accountBalanceId', v_ledger.account_balance_id,
    'accountType', v_ledger.account_type,
    'balance', v_ledger.balance,
    'currencyCode', v_ledger.currency_code,
    'createdAt', v_ledger.created_at
  );

  update public.mutation_idempotency_keys
  set status = 'COMPLETED',
      result_type = 'ledger_entry',
      result_id = v_ledger.ledger_entry_id,
      response_body = v_cached,
      completed_at = v_now
  where id = v_idempotency.id;

  return query select
    'applied'::text,
    v_ledger.ledger_entry_id,
    v_ledger.account_balance_id,
    v_ledger.account_type,
    v_ledger.balance,
    v_ledger.currency_code,
    v_ledger.created_at;
end;
$function$

CREATE OR REPLACE FUNCTION public.seed_initial_player_balances(p_game_session_id uuid, p_amount numeric, p_account_type text DEFAULT 'cash'::text, p_currency_code text DEFAULT 'ECO'::text, p_created_by_id uuid DEFAULT NULL::uuid, p_reason text DEFAULT 'Initial balance seed'::text, p_request_id text DEFAULT NULL::text)
 RETURNS TABLE(created_count integer, skipped_count integer, account_type text, currency_code text, seed_amount numeric, created_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_player record;
  v_game_exists boolean;
  v_balance_exists boolean;
  v_created_count integer := 0;
  v_skipped_count integer := 0;
  v_account_type text := btrim(coalesce(p_account_type, 'cash'));
  v_currency_code text := upper(btrim(coalesce(p_currency_code, 'ECO')));
  v_reason text := btrim(coalesce(p_reason, 'Initial balance seed'));
begin
  if p_game_session_id is null then
    raise exception 'GAME_SESSION_REQUIRED'
      using errcode = 'P0001';
  end if;

  select exists (
    select 1
    from public.game_sessions
    where id = p_game_session_id
      and status = 'active'
  )
  into v_game_exists;

  if not v_game_exists then
    raise exception 'GAME_SESSION_NOT_FOUND'
      using errcode = 'P0001';
  end if;

  if p_amount is null or p_amount <= 0 then
    raise exception 'SEED_AMOUNT_REQUIRED'
      using errcode = 'P0001';
  end if;

  if length(v_account_type) = 0 then
    raise exception 'ACCOUNT_TYPE_REQUIRED'
      using errcode = 'P0001';
  end if;

  if length(v_currency_code) < 3 or length(v_currency_code) > 16 then
    raise exception 'INVALID_CURRENCY_CODE'
      using errcode = 'P0001';
  end if;

  if length(v_reason) = 0 then
    v_reason := 'Initial balance seed';
  end if;

  for v_player in
    select id
    from public.players
    where game_session_id = p_game_session_id
      and status = 'active'
    order by created_at asc
  loop
    select exists (
      select 1
      from public.account_balances
      where game_session_id = p_game_session_id
        and player_id = v_player.id
        and account_type = v_account_type
        and currency_code = v_currency_code
    )
    into v_balance_exists;

    if v_balance_exists then
      v_skipped_count := v_skipped_count + 1;
    else
      perform 1
      from public.record_player_ledger_entry(
        p_game_session_id,
        v_player.id,
        v_account_type,
        p_amount,
        v_currency_code,
        'credit',
        'setup',
        'initial_balance_seed',
        null,
        'staff_user',
        p_created_by_id,
        jsonb_build_object(
          'requestId', p_request_id,
          'reason', v_reason,
          'source', 'classroom_api_edge_initial_balance_seed'
        )
      );

      v_created_count := v_created_count + 1;
    end if;
  end loop;

  return query
  select
    v_created_count,
    v_skipped_count,
    v_account_type,
    v_currency_code,
    p_amount,
    now();
end;
$function$

