CREATE OR REPLACE FUNCTION public.set_player_identity_and_access_code(p_game_session_id uuid, p_player_id uuid, p_player_identifier text, p_player_identifier_normalized text, p_access_code_hash text DEFAULT NULL::text)
 RETURNS TABLE(player_id uuid, player_identifier text, player_status text, credential_created_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_identifier text := nullif(btrim(coalesce(p_player_identifier, '')), '');
  v_identifier_normalized text := nullif(btrim(coalesce(p_player_identifier_normalized, '')), '');
  v_access_code_hash text := nullif(btrim(coalesce(p_access_code_hash, '')), '');
  v_player public.players%rowtype;
  v_credential_created_at timestamptz := null;
begin
  if p_game_session_id is null or p_player_id is null then
    raise exception 'PLAYER_SCOPE_REQUIRED' using errcode = 'P0001';
  end if;

  if v_identifier is null or v_identifier_normalized is null then
    raise exception 'PLAYER_IDENTIFIER_REQUIRED' using errcode = 'P0001';
  end if;

  update public.players as target_player
  set
    player_identifier = v_identifier,
    player_identifier_normalized = v_identifier_normalized,
    updated_at = now()
  where target_player.id = p_player_id
    and target_player.game_session_id = p_game_session_id
    and target_player.status = 'active'
  returning target_player.* into v_player;

  if v_player.id is null then
    raise exception 'PLAYER_NOT_FOUND' using errcode = 'P0001';
  end if;

  if v_access_code_hash is not null then
    update public.player_access_credentials as existing_credential
    set
      status = 'revoked',
      revoked_at = now(),
      updated_at = now()
    where existing_credential.game_session_id = p_game_session_id
      and existing_credential.player_id = p_player_id
      and existing_credential.status = 'active';

    insert into public.player_access_credentials (
      game_session_id,
      player_id,
      normalized_student_code_hash,
      status
    )
    values (
      p_game_session_id,
      p_player_id,
      v_access_code_hash,
      'active'
    )
    returning player_access_credentials.created_at into v_credential_created_at;
  end if;

  return query
  select
    v_player.id,
    v_player.player_identifier,
    v_player.status,
    v_credential_created_at;
exception
  when unique_violation then
    if exists (
      select 1
      from public.players as conflicting_player
      where conflicting_player.game_session_id = p_game_session_id
        and conflicting_player.player_identifier_normalized = v_identifier_normalized
        and conflicting_player.id <> p_player_id
        and conflicting_player.status = 'active'
    ) then
      raise exception 'PLAYER_IDENTIFIER_CONFLICT' using errcode = 'P0001';
    end if;

    if v_access_code_hash is not null and exists (
      select 1
      from public.player_access_credentials as conflicting_credential
      where conflicting_credential.game_session_id = p_game_session_id
        and conflicting_credential.normalized_student_code_hash = v_access_code_hash
        and conflicting_credential.player_id <> p_player_id
        and conflicting_credential.status = 'active'
    ) then
      raise exception 'PLAYER_ACCESS_CODE_CONFLICT' using errcode = 'P0001';
    end if;

    raise;
end;
$function$

CREATE OR REPLACE FUNCTION public.stock_market_timezone_for_game(p_game_session_id uuid)
 RETURNS text
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_timezone text;
begin
  select nullif(btrim(settings.stock_market_window ->> 'timezone'), '')
  into v_timezone
  from public.game_settings settings
  where settings.game_session_id = p_game_session_id;

  if v_timezone is null then
    raise exception 'STOCK_MARKET_TIMEZONE_REQUIRED';
  end if;

  if not exists (
    select 1
    from pg_timezone_names zone
    where zone.name = v_timezone
  ) then
    raise exception 'STOCK_MARKET_TIMEZONE_INVALID';
  end if;

  return v_timezone;
end;
$function$

CREATE OR REPLACE FUNCTION public.transition_game_lifecycle_atomic_v1(p_game_session_id uuid, p_staff_user_id uuid, p_action text, p_idempotency_key text, p_expected_version bigint DEFAULT NULL::bigint)
 RETURNS TABLE(transition_outcome text, transition_action text, previous_state text, lifecycle_state text, operational_status text, lifecycle_version bigint, sessions_revoked integer, join_code_status text, allowed_actions text[], started_at timestamp with time zone, paused_at timestamp with time zone, resumed_at timestamp with time zone, ended_at timestamp with time zone, archived_at timestamp with time zone, updated_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_action text := lower(btrim(coalesce(p_action, '')));
  v_key text := btrim(coalesce(p_idempotency_key, ''));
  v_game public.game_sessions%rowtype;
  v_existing public.game_lifecycle_transition_requests%rowtype;
  v_previous text;
  v_next text;
  v_projection text;
  v_outcome text := 'applied';
  v_sessions_revoked integer := 0;
  v_changed boolean := false;
  v_now timestamptz := now();
begin
  if p_game_session_id is null or p_staff_user_id is null then
    raise exception 'GAME_LIFECYCLE_TRANSITION_INVALID' using errcode = 'P0001';
  end if;
  if v_action not in ('start', 'pause', 'resume', 'end', 'archive', 'revoke_sessions') then
    raise exception 'GAME_LIFECYCLE_ACTION_INVALID' using errcode = 'P0001';
  end if;
  if length(v_key) = 0 or length(v_key) > 128 or v_key !~ '^[A-Za-z0-9][A-Za-z0-9._:-]*$' then
    raise exception 'GAME_LIFECYCLE_IDEMPOTENCY_INVALID' using errcode = 'P0001';
  end if;
  if p_expected_version is not null and p_expected_version < 1 then
    raise exception 'GAME_LIFECYCLE_VERSION_INVALID' using errcode = 'P0001';
  end if;

  perform pg_advisory_xact_lock(
    hashtextextended(p_game_session_id::text || ':' || v_key, 0)
  );

  select *
  into v_existing
  from public.game_lifecycle_transition_requests
  where game_session_id = p_game_session_id
    and idempotency_key = v_key;

  if found then
    if v_existing.action <> v_action then
      raise exception 'GAME_LIFECYCLE_IDEMPOTENCY_CONFLICT' using errcode = 'P0001';
    end if;

    select *
    into v_game
    from public.game_sessions
    where id = p_game_session_id
      and owner_staff_user_id = p_staff_user_id;

    if not found then
      raise exception 'GAME_LIFECYCLE_SCOPE_FORBIDDEN' using errcode = 'P0001';
    end if;

    return query
    select
      'replayed'::text,
      v_existing.action,
      v_existing.previous_state,
      v_existing.lifecycle_state,
      v_existing.operational_status,
      v_existing.lifecycle_version,
      v_existing.sessions_revoked,
      v_existing.join_code_status,
      case v_existing.lifecycle_state
        when 'draft' then array['start', 'revoke_sessions']::text[]
        when 'active' then array['pause', 'end', 'revoke_sessions']::text[]
        when 'paused' then array['resume', 'end', 'revoke_sessions']::text[]
        when 'ended' then array['archive', 'revoke_sessions']::text[]
        when 'archived' then array['revoke_sessions']::text[]
        else array[]::text[]
      end,
      v_existing.started_at,
      v_existing.paused_at,
      v_existing.resumed_at,
      v_existing.ended_at,
      v_existing.archived_at,
      v_existing.game_updated_at;
    return;
  end if;

  select *
  into v_game
  from public.game_sessions
  where id = p_game_session_id
    and owner_staff_user_id = p_staff_user_id
  for update;

  if not found then
    raise exception 'GAME_LIFECYCLE_SCOPE_FORBIDDEN' using errcode = 'P0001';
  end if;

  if p_expected_version is not null and v_game.lifecycle_version <> p_expected_version then
    raise exception 'GAME_LIFECYCLE_VERSION_CONFLICT' using errcode = 'P0001';
  end if;

  v_previous := v_game.lifecycle_state;
  v_next := v_previous;

  if v_action = 'start' then
    if v_previous = 'draft' then v_next := 'active';
    elsif v_previous = 'active' then v_outcome := 'already_current';
    else raise exception 'GAME_LIFECYCLE_TRANSITION_INVALID' using errcode = 'P0001';
    end if;
  elsif v_action = 'pause' then
    if v_previous = 'active' then v_next := 'paused';
    elsif v_previous = 'paused' then v_outcome := 'already_current';
    else raise exception 'GAME_LIFECYCLE_TRANSITION_INVALID' using errcode = 'P0001';
    end if;
  elsif v_action = 'resume' then
    if v_previous = 'paused' then v_next := 'active';
    elsif v_previous = 'active' then v_outcome := 'already_current';
    else raise exception 'GAME_LIFECYCLE_TRANSITION_INVALID' using errcode = 'P0001';
    end if;
  elsif v_action = 'end' then
    if v_previous in ('active', 'paused') then v_next := 'ended';
    elsif v_previous = 'ended' then v_outcome := 'already_current';
    else raise exception 'GAME_LIFECYCLE_TRANSITION_INVALID' using errcode = 'P0001';
    end if;
  elsif v_action = 'archive' then
    if v_previous = 'ended' then v_next := 'archived';
    elsif v_previous = 'archived' then v_outcome := 'already_current';
    else raise exception 'GAME_LIFECYCLE_TRANSITION_INVALID' using errcode = 'P0001';
    end if;
  end if;

  v_changed := v_next <> v_previous;

  if v_action in ('end', 'archive', 'revoke_sessions') then
    update public.player_sessions
    set
      status = 'revoked',
      revoked_at = coalesce(revoked_at, v_now)
    where game_session_id = p_game_session_id
      and status = 'active';
    get diagnostics v_sessions_revoked = row_count;
    if v_action = 'revoke_sessions' and v_sessions_revoked = 0 then
      v_outcome := 'already_current';
    end if;
  end if;

  v_projection := case v_next
    when 'active' then 'active'
    when 'draft' then 'disabled'
    when 'paused' then 'disabled'
    when 'ended' then 'archived'
    when 'archived' then 'archived'
  end;

  if v_changed or v_sessions_revoked > 0 then
    update public.game_sessions
    set
      lifecycle_state = v_next,
      status = v_projection,
      lifecycle_version = lifecycle_version + 1,
      started_at = case
        when v_action = 'start' then coalesce(started_at, v_now)
        else started_at
      end,
      paused_at = case when v_action = 'pause' then v_now else paused_at end,
      resumed_at = case when v_action = 'resume' then v_now else resumed_at end,
      ended_at = case when v_action = 'end' then coalesce(ended_at, v_now) else ended_at end,
      archived_at = case when v_action = 'archive' then coalesce(archived_at, v_now) else archived_at end,
      game_join_code_status = case
        when v_action in ('end', 'archive') then 'revoked'
        else game_join_code_status
      end,
      game_join_code_hash = case
        when v_action in ('end', 'archive') then null
        else game_join_code_hash
      end
    where id = p_game_session_id
    returning * into v_game;
  end if;

  insert into public.game_lifecycle_transition_requests (
    game_session_id,
    staff_user_id,
    idempotency_key,
    action,
    previous_state,
    lifecycle_state,
    operational_status,
    lifecycle_version,
    sessions_revoked,
    join_code_status,
    started_at,
    paused_at,
    resumed_at,
    ended_at,
    archived_at,
    game_updated_at,
    outcome,
    completed_at
  ) values (
    p_game_session_id,
    p_staff_user_id,
    v_key,
    v_action,
    v_previous,
    v_game.lifecycle_state,
    v_game.status,
    v_game.lifecycle_version,
    v_sessions_revoked,
    v_game.game_join_code_status,
    v_game.started_at,
    v_game.paused_at,
    v_game.resumed_at,
    v_game.ended_at,
    v_game.archived_at,
    v_game.updated_at,
    v_outcome,
    v_now
  );

  insert into public.audit_log (
    game_session_id,
    actor_type,
    actor_id,
    action,
    target_type,
    target_id,
    metadata
  ) values (
    p_game_session_id,
    'staff_user',
    p_staff_user_id,
    'game.lifecycle.' || v_action,
    'game_session',
    p_game_session_id,
    jsonb_build_object(
      'previous_state', v_previous,
      'lifecycle_state', v_game.lifecycle_state,
      'operational_status', v_game.status,
      'lifecycle_version', v_game.lifecycle_version,
      'sessions_revoked', v_sessions_revoked,
      'join_code_status', v_game.game_join_code_status,
      'outcome', v_outcome
    )
  );

  return query
  select
    v_outcome,
    v_action,
    v_previous,
    v_game.lifecycle_state,
    v_game.status,
    v_game.lifecycle_version,
    v_sessions_revoked,
    v_game.game_join_code_status,
    case v_game.lifecycle_state
      when 'draft' then array['start', 'revoke_sessions']::text[]
      when 'active' then array['pause', 'end', 'revoke_sessions']::text[]
      when 'paused' then array['resume', 'end', 'revoke_sessions']::text[]
      when 'ended' then array['archive', 'revoke_sessions']::text[]
      when 'archived' then array['revoke_sessions']::text[]
      else array[]::text[]
    end,
    v_game.started_at,
    v_game.paused_at,
    v_game.resumed_at,
    v_game.ended_at,
    v_game.archived_at,
    v_game.updated_at;
end;
$function$

CREATE OR REPLACE FUNCTION public.validate_required_stock_market_timezone()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_timezone text;
begin
  if jsonb_typeof(new.stock_market_window) <> 'object' then
    raise exception 'STOCK_MARKET_TIMEZONE_REQUIRED';
  end if;

  v_timezone := nullif(btrim(new.stock_market_window ->> 'timezone'), '');

  if v_timezone is null then
    raise exception 'STOCK_MARKET_TIMEZONE_REQUIRED';
  end if;

  if not exists (
    select 1
    from pg_timezone_names zone
    where zone.name = v_timezone
  ) then
    raise exception 'STOCK_MARKET_TIMEZONE_INVALID';
  end if;

  new.stock_market_window := jsonb_set(
    new.stock_market_window,
    '{timezone}',
    to_jsonb(v_timezone),
    true
  );

  return new;
end;
$function$
